/**
 * StackOwl — Pellet Store
 *
 * Manages the storage and retrieval of "Pellets" — structured,
 * reusable knowledge artifacts generated by owls.
 */

import { join } from "node:path";
import {
  mkdir,
  readFile,
  writeFile,
  readdir,
  unlink,
  rename,
} from "node:fs/promises";
import { existsSync } from "node:fs";
import matter from "gray-matter";
import type { ModelProvider } from "../providers/base.js";

export interface Pellet {
  id: string; // The filename (without .md)
  title: string;
  generatedAt: string;
  source: string;
  owls: string[];
  tags: string[];
  content: string; // The raw markdown body
  version: number;
}

export class PelletStore {
  private pelletsDir: string;
  private provider?: ModelProvider;
  private vectorIndex: Record<string, number[]> = {};
  private indexPath: string;
  private embeddingsSupported: boolean = true;

  constructor(workspacePath: string, provider?: ModelProvider) {
    this.pelletsDir = join(workspacePath, "pellets");
    this.provider = provider;
    this.indexPath = join(this.pelletsDir, "vector_index.json");
  }

  /** Ensure the pellets directory and index exists */
  async init(): Promise<void> {
    if (!existsSync(this.pelletsDir)) {
      await mkdir(this.pelletsDir, { recursive: true });
    }

    if (existsSync(this.indexPath)) {
      try {
        const raw = await readFile(this.indexPath, "utf-8");
        this.vectorIndex = JSON.parse(raw);
      } catch (e) {
        console.error(
          "[PelletStore] Failed to load vector index, starting fresh.",
          e,
        );
        this.vectorIndex = {};
      }
    }
  }

  /**
   * Save a pellet to disk.
   */
  async save(pellet: Pellet): Promise<void> {
    await this.init();

    const frontmatter = {
      title: pellet.title,
      generated_at: pellet.generatedAt,
      source: pellet.source,
      owls: pellet.owls,
      tags: pellet.tags,
      version: pellet.version,
    };

    const raw = matter.stringify(pellet.content, frontmatter);
    const mdPath = join(this.pelletsDir, `${pellet.id}.tmp.md`);
    const finalPath = join(this.pelletsDir, `${pellet.id}.md`);

    // Write safely to tmp then rename
    await writeFile(mdPath, raw, "utf-8");
    await rename(mdPath, finalPath);

    // Generate and save embedding if provider exists and supports embeddings
    if (this.provider) {
      try {
        const textToEmbed = `${pellet.title}\n\n${pellet.tags.join(", ")}\n\n${pellet.content}`;
        const response = await this.provider.embed(textToEmbed);
        this.vectorIndex[pellet.id] = response.embedding;
        await writeFile(
          this.indexPath,
          JSON.stringify(this.vectorIndex, null, 2),
          "utf-8",
        );
      } catch (error) {
        // Model doesn't support embeddings - use keyword-based search instead
        this.embeddingsSupported = false;
        console.warn(
          `[PelletStore] Embeddings not supported, using keyword search`,
        );
        // Store a marker so we know to use text search
        this.vectorIndex[pellet.id] = [];
        await writeFile(
          this.indexPath,
          JSON.stringify(this.vectorIndex, null, 2),
          "utf-8",
        );
      }
    }
  }

  /**
   * Read a specific pellet by ID.
   */
  async get(id: string): Promise<Pellet | null> {
    const mdPath = join(this.pelletsDir, `${id}.md`);
    if (!existsSync(mdPath)) return null;

    try {
      const raw = await readFile(mdPath, "utf-8");
      const { data, content } = matter(raw);

      return {
        id,
        title: data.title || id,
        generatedAt: data.generated_at || new Date().toISOString(),
        source: data.source || "Unknown",
        owls: Array.isArray(data.owls) ? data.owls : [],
        tags: Array.isArray(data.tags) ? data.tags : [],
        version: data.version || 1,
        content: content.trim(),
      };
    } catch (error) {
      console.error(`[PelletStore] Failed to read pellet ${id}:`, error);
      return null;
    }
  }

  /**
   * List all available pellets.
   */
  async listAll(): Promise<Pellet[]> {
    await this.init();

    try {
      const files = await readdir(this.pelletsDir);
      const pellets: Pellet[] = [];

      for (const file of files) {
        if (file.endsWith(".md")) {
          const id = file.replace(".md", "");
          const pellet = await this.get(id);
          if (pellet) pellets.push(pellet);
        }
      }

      // Sort by most recently generated
      return pellets.sort((a, b) => {
        return (
          new Date(b.generatedAt).getTime() - new Date(a.generatedAt).getTime()
        );
      });
    } catch (error) {
      console.error("[PelletStore] Failed to list pellets:", error);
      return [];
    }
  }

  /**
   * Delete a pellet by ID and its embedding.
   */
  async delete(id: string): Promise<boolean> {
    const mdPath = join(this.pelletsDir, `${id}.md`);
    if (existsSync(mdPath)) {
      await unlink(mdPath);
      if (this.vectorIndex[id]) {
        delete this.vectorIndex[id];
        await writeFile(
          this.indexPath,
          JSON.stringify(this.vectorIndex, null, 2),
          "utf-8",
        );
      }
      return true;
    }
    return false;
  }

  /**
   * Semantic search pellets by query using Cosine Similarity.
   * Falls back to text search if no provider is available or embedding fails.
   */
  async search(query: string): Promise<Pellet[]> {
    const all = await this.listAll();
    if (all.length === 0) return [];

    // If no provider or no query or embeddings not supported, fallback to text search
    if (!this.provider || !query.trim() || !this.embeddingsSupported) {
      return this.textSearch(query, all);
    }

    // Check if we have any valid embeddings
    const hasValidEmbeddings = Object.values(this.vectorIndex).some(
      (v) => v && v.length > 0,
    );

    // If no valid embeddings, use text search
    if (!hasValidEmbeddings) {
      return this.textSearch(query, all);
    }

    try {
      const queryResponse = await this.provider.embed(query);
      const queryVec = queryResponse.embedding;

      // Score all pellets with a valid embedding
      const scored: { pellet: Pellet; score: number }[] = [];

      for (const p of all) {
        const vec = this.vectorIndex[p.id];
        if (vec && vec.length > 0) {
          scored.push({
            pellet: p,
            score: this.cosineSimilarity(queryVec, vec),
          });
        }
      }

      // If no pellets have embeddings, fallback to text search
      if (scored.length === 0) {
        return this.textSearch(query, all);
      }

      // Sort by highest similarity
      scored.sort((a, b) => b.score - a.score);

      // Return top results (e.g. top 5 or anything above threshold)
      // Or just return the sorted list of all embedded pellets
      return scored.map((s) => s.pellet);
    } catch (error) {
      console.error(
        "[PelletStore] Semantic search failed, falling back to text search:",
        error,
      );
      return this.textSearch(query, all);
    }
  }

  private textSearch(query: string, all: Pellet[]): Pellet[] {
    const lowerQuery = query.toLowerCase();
    const queryWords = lowerQuery.split(/\W+/).filter((w) => w.length > 2);

    // Score each pellet by relevance
    const scored: { pellet: Pellet; score: number }[] = [];

    for (const p of all) {
      let score = 0;
      const titleLower = p.title.toLowerCase();
      const contentLower = p.content.toLowerCase();
      const tagsLower = p.tags.map((t) => t.toLowerCase());

      // Title match (highest weight)
      if (titleLower.includes(lowerQuery)) score += 10;
      for (const word of queryWords) {
        if (titleLower.includes(word)) score += 5;
      }

      // Tag match (high weight)
      for (const tag of tagsLower) {
        if (tag.includes(lowerQuery)) score += 5;
        for (const word of queryWords) {
          if (tag.includes(word)) score += 2;
        }
      }

      // Content match
      if (contentLower.includes(lowerQuery)) score += 3;
      for (const word of queryWords) {
        if (contentLower.includes(word)) score += 1;
      }

      if (score > 0) {
        scored.push({ pellet: p, score });
      }
    }

    // Sort by score descending
    scored.sort((a, b) => b.score - a.score);
    return scored.map((s) => s.pellet);
  }

  private cosineSimilarity(a: number[], b: number[]): number {
    if (a.length !== b.length) return 0;
    let dotProduct = 0;
    let normA = 0;
    let normB = 0;
    for (let i = 0; i < a.length; i++) {
      dotProduct += a[i] * b[i];
      normA += a[i] * a[i];
      normB += b[i] * b[i];
    }
    if (normA === 0 || normB === 0) return 0;
    return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
  }
}
